#!/bin/bash
whois $1 | awk -F: 'BEGIN {split("Registrant,Admin,Tech", s, ","); split("Name,Organization,Street,City,State/Province,Postal Code,Country,Phone,Phone Ext,Fax,Fax Ext,Email", f, ",")} /^[ 	]*Registrant/ {sec="Registrant"} /^[ 	]*Admin/ {sec="Admin"} /^[ 	]*Tech/ {sec="Tech"} /:/ {k=$1; v=$0; sub(/^[^:]*:/, "", v); gsub(/^[ 	]+|[ 	]+$/, "", k); gsub(/^[ 	]+|[ 	]+$/, "", v); gsub(/^Registrant[ 	]*/, "", k); gsub(/^Admin[ 	]*/, "", k); gsub(/^Tech[ 	]*/, "", k); gsub(/[ 	]*Contact$/, "", k); if (k=="State"||k=="Province") k="State/Province"; if (k=="PostalCode") k="Postal Code"; if (sec!="" && k!="") {if (k=="Street") data[sec, k]=(data[sec, k]==""?"":data[sec, k]" ") v; else if (v!="" || data[sec, k]=="") data[sec, k]=v}} END {for (i=1; i<=3; i++) {for (j=1; j<=12; j++) {df=f[j]; val=data[s[i], f[j]]; if (df~/Ext$/) df=df":"; if (df=="Street" && val!="") val=val" "; print s[i] " " df "," val}}}' > $1.csv
